codeExample1.code:
// 1. Declare variables
const country = "United States";
let score = 100;

console.log("Starting score in " + country + ":", score);

// 2. Perform reassignment
score = 150; 
console.log("Updated score:", score);

// 3. Trying to reassign a const throws an error
try {
  country = "Canada"; 
} catch (error) {
  console.log("Error caught safely:", error.message);
}

codeExample2.code:
let container = "Book";
console.log("Initial type:", typeof container);

container = 42;
console.log("Type after number assign:", typeof container);

container = { title: "JS Guide", pages: 200 };
console.log("Type after object assign:", typeof container);

console.log("Checking null:", typeof null);
console.log("Checking undefined:", typeof undefined);

commonMistakes.badCode:
let user; // Declared but empty
if (user === null) {
  console.log("User is null"); // This will NEVER run!
}

commonMistakes.goodCode:
let user; 
if (user === undefined) {
  console.log("User is undefined (not set yet)");
}
// Or to check both:
if (user == null) {
  console.log("User is either null or undefined");
}

