function checkVariable(val) {
  const type = typeof val;
  console.log("Type reported:", type);
  if (type === "object" && val === null) {
    console.log("Warning: This is actually null (the historic JS typeof bug)!");
  }
}
checkVariable(null);
checkVariable({ name: "Alice" });

